@EventPattern('SchemaPublished')
async onSchemaPublished(event: SchemaPublished): Promise<void> {
  const deps = await this.loadAllDependencies(event.tenantId);
  const topology = this.buildTopology(deps);
  await this.db.storeDocument('xiigen-flow-definitions', topology);
  await this.queue.enqueue('DagRebuildCompleted', { schemaType: event.schemaType });
}
